        }

        var img = link.queryselector("img");
        if (img && !img.alt) {
            img.alt = "download notice";
        }

    });

});

document.addeventlistener("domcontentloaded", function () {

    /* 1️⃣ fix images without alt */
    document.queryselectorall("img").foreach(function(img){
        if (!img.hasattribute("alt")) {
            img.setattribute("alt", "");
        }
    });

    /* 2️⃣ convert clickable divs to accessible buttons */
    document.queryselectorall("div[onclick]").foreach(function(div){
        div.setattribute("role", "button");
        div.setattribute("tabindex", "0");

        div.addeventlistener("keydown", function(e){
            if (e.key === "enter" || e.key === " ") {
                e.preventdefault();
                div.click();
            }
        });
    });

    /* 3️⃣ hide decorative icons from screen readers */
    document.queryselectorall("i, svg").foreach(function(icon){
        if (!icon.closest("button") && !icon.closest("a")) {
            icon.setattribute("aria-hidden", "true");
        }
    });

    /* 4️⃣ ensure buttons have accessible name */
    document.queryselectorall("button").foreach(function(btn){
        if (!btn.innertext.trim()) {
            btn.setattribute("aria-label", "button");
        }
    });

    /* 5️⃣ add landmark role to main content (if missing) */
    if (!document.queryselector("main")) {
        var maindiv = document.getelementbyid("main-content");
        if (maindiv) {
            maindiv.setattribute("role", "main");
        }
    }

});
